mapper.select:
select r.id, r.plan_id, r.process_id, r.reviewed_user_id, r.reviewed_user_nick_name, r.reviewer_user_id, r.reviewer_user_nick_name, r.status, r.type, r.version, r.review_create_time,r.review_finish_time, r.reviewed_remark, r.reviewer_remark,
        plan.name as plan_name,
        process.name as process_name
from review r
left join submission_plan plan on r.plan_id = plan.id
left join submission_process process on r.process_id = process.id

    and r.plan_id = #{planId}
    and r.reviewed_user_id = #{reviewedUserId}
    and r.reviewer_user_id = #{reviewerUserId}


            and r.status != 1
            and r.status = #{status}


    and r.review_create_time >= #{reviewCreateTimeStart}
    and r.review_create_time <= #{reviewCreateTimeEnd}

order by r.review_create_time desc

select r1.*
from review r1
inner join (
    select process_id, type, max(version) as max_version
    from review
    where process_id = #{processId}
    group by process_id, type
) r2 on r1.process_id = r2.process_id and r1.type = r2.type and r1.version = r2.max_version
where r1.process_id = #{processId}

mapper.update:
update review
status = #{status}, reviewer_remark = #{reviewerRemark}, review_finish_time = #{reviewFinishTime}, review_create_time = #{reviewCreateTime}, update_time = #{updateTime}
where id = #{id}
